#!/usr/bin/env python3
"""
JARVIS — Single File Edition
Just run: python start.py
Works on Mac, Windows, and Linux. No other files needed.
"""

import os, sys, platform, subprocess, threading, time, webbrowser, json, base64
from http.server import HTTPServer, BaseHTTPRequestHandler

OS  = platform.system()
DIR = os.path.dirname(os.path.abspath(__file__))
WEB_PORT  = 9000
CTRL_PORT = 8888

# ── Embedded JARVIS frontend (base64) ─────────────────────────────────────────
_HTML_B64 = ""
HTML = base64.b64decode(_HTML_B64).decode('utf-8')


# ─────────────────────────────────────────────────────────────────────────────
#  WEB SERVER — serves JARVIS HTML from memory (no external files)
# ─────────────────────────────────────────────────────────────────────────────
class WebHandler(BaseHTTPRequestHandler):
    def do_GET(self):
        self.send_response(200)
        self.send_header('Content-Type', 'text/html; charset=utf-8')
        self.send_header('Access-Control-Allow-Origin', '*')
        self.end_headers()
        self.wfile.write(HTML.encode('utf-8'))
    def log_message(self, *a): pass

