# ─────────────────────────────────────────────────────────────────────────────
#  KILL OLD PROCESSES ON OUR PORTS
# ─────────────────────────────────────────────────────────────────────────────
def kill_port(port):
    try:
        if OS == 'Windows':
            result = subprocess.run(
                f'netstat -ano | findstr ":{port}"',
                shell=True, capture_output=True, text=True)
            for line in result.stdout.splitlines():
                parts = line.strip().split()
                if parts:
                    subprocess.run(f'taskkill /PID {parts[-1]} /F',
                                   shell=True, capture_output=True)
        else:
            subprocess.run(f"lsof -ti:{port} | xargs kill -9 2>/dev/null",
                           shell=True, capture_output=True)
    except: pass

kill_port(WEB_PORT)
kill_port(CTRL_PORT)
time.sleep(0.3)

# ─────────────────────────────────────────────────────────────────────────────
#  CONTROL SERVER  (handles all OS-level commands from JARVIS)
# ─────────────────────────────────────────────────────────────────────────────
class ControlHandler(BaseHTTPRequestHandler):

    def do_OPTIONS(self):
        self.send_response(200)
        self.send_header('Access-Control-Allow-Origin', '*')
        self.send_header('Access-Control-Allow-Methods', 'POST, OPTIONS')
        self.send_header('Access-Control-Allow-Headers', 'Content-Type')
        self.end_headers()

    def do_GET(self):
        self.send_response(200)
        self.send_header('Content-Type', 'application/json')
        self.send_header('Access-Control-Allow-Origin', '*')
        self.end_headers()
        self.wfile.write(json.dumps({'status': 'online', 'os': OS}).encode())

    def do_POST(self):
        length = int(self.headers.get('Content-Length', 0))
        body   = self.rfile.read(length)
        try:    data = json.loads(body.decode('utf-8'))
        except: data = {}

        cmd  = data.get('command', '')
        args = data.get('args', '')
        res  = {'success': False, 'message': 'Unknown command'}

        try:
            # ── Open URL in default browser ───────────────────────────────
            if cmd == 'open_url':
                if OS == 'Darwin':  subprocess.Popen(['open', args])
                elif OS == 'Windows': os.startfile(args)
                else: subprocess.Popen(['xdg-open', args])
                res = {'success': True, 'message': f'Opened {args}'}

            # ── Open native app ───────────────────────────────────────────
            elif cmd == 'open_app':
                if OS == 'Darwin':   subprocess.Popen(['open', '-a', args])
                elif OS == 'Windows': subprocess.Popen(['start', '', args], shell=True)
                else: subprocess.Popen([args.lower()])
                res = {'success': True, 'message': f'Opened {args}'}

            # ── Close browser tab ─────────────────────────────────────────
            elif cmd == 'close_tab':
                if OS == 'Darwin':
                    subprocess.run(['osascript', '-e',
                        'tell application "Google Chrome" to close current tab of front window'])
                elif OS == 'Windows':
                    import ctypes
                    subprocess.run(['powershell', '-Command',
                        'Add-Type -AssemblyName System.Windows.Forms; [System.Windows.Forms.SendKeys]::SendWait("^w")'])
                res = {'success': True, 'message': 'Tab closed'}

            # ── New browser tab ───────────────────────────────────────────
            elif cmd == 'new_tab':
                url = args if args else 'about:blank'
                if OS == 'Darwin':
                    subprocess.run(['osascript', '-e',
                        f'tell application "Google Chrome" to activate\n'
                        f'tell front window of application "Google Chrome" to make new tab with properties {{URL:"{url}"}}'])
                else:
                    webbrowser.open_new_tab(url)
                res = {'success': True, 'message': 'New tab opened'}

            # ── Volume set (0-100) ────────────────────────────────────────
            elif cmd == 'volume':
                level = max(0, min(100, int(args)))
                if OS == 'Darwin':
                    subprocess.run(['osascript', '-e', f'set volume output volume {level}'])
                elif OS == 'Windows':
                    subprocess.run(['nircmd', 'setsysvolume', str(int(level / 100 * 65535))],
                                   capture_output=True)
                elif OS == 'Linux':
                    subprocess.run(['amixer', '-D', 'pulse', 'sset', 'Master', f'{level}%'])
                res = {'success': True, 'message': f'Volume set to {level}%'}

            # ── Volume up / down ──────────────────────────────────────────
            elif cmd == 'volume_up':
                if OS == 'Darwin':
                    subprocess.run(['osascript', '-e',
                        'set volume output volume (output volume of (get volume settings) + 10)'])
                elif OS == 'Linux':
                    subprocess.run(['amixer', '-D', 'pulse', 'sset', 'Master', '10%+'])
                res = {'success': True, 'message': 'Volume up'}

            elif cmd == 'volume_down':
                if OS == 'Darwin':
                    subprocess.run(['osascript', '-e',
                        'set volume output volume (output volume of (get volume settings) - 10)'])
                elif OS == 'Linux':
                    subprocess.run(['amixer', '-D', 'pulse', 'sset', 'Master', '10%-'])
                res = {'success': True, 'message': 'Volume down'}

            # ── Mute / Unmute ─────────────────────────────────────────────
            elif cmd == 'mute':
                if OS == 'Darwin':
                    subprocess.run(['osascript', '-e', 'set volume with output muted'])
                elif OS == 'Windows':
                    subprocess.run(['nircmd', 'mutesysvolume', '1'], capture_output=True)
                elif OS == 'Linux':
                    subprocess.run(['amixer', '-D', 'pulse', 'sset', 'Master', 'mute'])
                res = {'success': True, 'message': 'Muted'}

            elif cmd == 'unmute':
                if OS == 'Darwin':
                    subprocess.run(['osascript', '-e', 'set volume without output muted'])
                elif OS == 'Windows':
                    subprocess.run(['nircmd', 'mutesysvolume', '0'], capture_output=True)
                elif OS == 'Linux':
                    subprocess.run(['amixer', '-D', 'pulse', 'sset', 'Master', 'unmute'])
                res = {'success': True, 'message': 'Unmuted'}

            # ── Screenshot ────────────────────────────────────────────────
            elif cmd == 'screenshot':
                path = os.path.expanduser('~/Desktop/jarvis-screenshot.png')
                if OS == 'Darwin':
                    subprocess.run(['screencapture', '-x', path])
                elif OS == 'Windows':
                    subprocess.run(['powershell', '-Command',
                        f'Add-Type -AssemblyName System.Windows.Forms,System.Drawing;'
                        f'$s=[System.Windows.Forms.Screen]::PrimaryScreen.Bounds;'
                        f'$b=New-Object System.Drawing.Bitmap($s.Width,$s.Height);'
                        f'$g=[System.Drawing.Graphics]::FromImage($b);'
                        f'$g.CopyFromScreen($s.Location,[System.Drawing.Point]::Empty,$s.Size);'
                        f'$b.Save("{path}")'])
                elif OS == 'Linux':
                    subprocess.run(['scrot', path])
                res = {'success': True, 'message': 'Screenshot saved to Desktop'}

            # ── Lock screen ───────────────────────────────────────────────
            elif cmd == 'lock_screen':
                if OS == 'Darwin':
                    subprocess.Popen(['pmset', 'displaysleepnow'])
                elif OS == 'Windows':
                    subprocess.Popen(['rundll32.exe', 'user32.dll,LockWorkStation'])
                elif OS == 'Linux':
                    subprocess.Popen(['gnome-screensaver-command', '-l'])
                res = {'success': True, 'message': 'Screen locked'}

            # ── Sleep ─────────────────────────────────────────────────────
            elif cmd == 'sleep':
                if OS == 'Darwin':
                    subprocess.Popen(['pmset', 'sleepnow'])
                elif OS == 'Windows':
                    subprocess.Popen(['rundll32.exe', 'powrprof.dll,SetSuspendState', '0', '1', '0'])
                elif OS == 'Linux':
                    subprocess.Popen(['systemctl', 'suspend'])
                res = {'success': True, 'message': 'Sleeping'}

            # ── Battery ───────────────────────────────────────────────────
            elif cmd == 'battery':
                if OS == 'Darwin':
                    out = subprocess.run(['pmset', '-g', 'batt'], capture_output=True, text=True)
                    res = {'success': True, 'message': out.stdout}
                elif OS == 'Windows':
                    out = subprocess.run(['powershell', '-Command',
                        '(Get-WmiObject Win32_Battery).EstimatedChargeRemaining'],
                        capture_output=True, text=True)
                    res = {'success': True, 'message': out.stdout.strip() + '%'}
                elif OS == 'Linux':
                    try:
                        val = open('/sys/class/power_supply/BAT0/capacity').read().strip()
                        res = {'success': True, 'message': val + '%'}
                    except: res = {'success': False, 'message': 'Battery not found'}

            # ── Desktop notification ──────────────────────────────────────
            elif cmd == 'notify':
                title = data.get('title', 'JARVIS')
                msg   = args
                if OS == 'Darwin':
                    subprocess.run(['osascript', '-e',
                        f'display notification "{msg}" with title "{title}"'])
                elif OS == 'Windows':
                    subprocess.run(['powershell', '-Command',
                        f'[System.Reflection.Assembly]::LoadWithPartialName("System.Windows.Forms");'
                        f'[System.Windows.Forms.MessageBox]::Show("{msg}","{title}")'])
                elif OS == 'Linux':
                    subprocess.run(['notify-send', title, msg])
                res = {'success': True, 'message': 'Notification sent'}

            # ── Raw AppleScript (Mac only) ────────────────────────────────
            elif cmd == 'applescript':
                if OS == 'Darwin':
                    out = subprocess.run(['osascript', '-e', args],
                                         capture_output=True, text=True)
                    res = {'success': True, 'message': out.stdout.strip() or 'Done'}
                else:
                    res = {'success': False, 'message': 'Mac only'}

        except Exception as e:
            res = {'success': False, 'message': str(e)}

        self.send_response(200)
        self.send_header('Content-Type', 'application/json')
        self.send_header('Access-Control-Allow-Origin', '*')
        self.end_headers()
        self.wfile.write(json.dumps(res).encode())

    def log_message(self, *a): pass   # Keep terminal clean


def run_control_server():
    HTTPServer(('localhost', CTRL_PORT), ControlHandler).serve_forever()

# ─────────────────────────────────────────────────────────────────────────────
#  WEB SERVER  (serves jarvis.html)
# ─────────────────────────────────────────────────────────────────────────────

def run_web_server():
    HTTPServer(('localhost', WEB_PORT), WebHandler).serve_forever()

# ─────────────────────────────────────────────────────────────────────────────
#  START EVERYTHING
